import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        byte[] inputBytes = input.getBytes(StandardCharsets.UTF_8);

        if (inputBytes.length > 10) {
            System.out.println("Input string is too long. Please enter a string with at most 10 characters.");
            return;
        }

        char[] buffer = new char[10];

        for (int i = 0; i < inputBytes.length; i++) {
            buffer[i] = (char)inputBytes[i];
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
